import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  X, Play, Pause, ScrollText, ChevronRight, Sparkles, 
  RefreshCw, BookOpen, Volume2, SkipBack, SkipForward, 
  ArrowLeft, Search, Bookmark, History, LayoutGrid, 
  Library, Trophy, Target, Type, Mic2, FileText, 
  Compass, Feather, User, Menu, Sliders, Loader2, Star,
  Info, ChevronDown, ChevronUp, Languages
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { SanZiJingVerse, CharAnalysis } from '../lib/sanzijingData';
import { GoogleGenAI } from "@google/genai";
import sql from '../lib/neon';

type ViewType = 'hub' | 'reader' | 'stories' | 'profile';

const ThreeCharacterApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [verses, setVerses] = useState<SanZiJingVerse[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [currentCharIdx, setCurrentCharIdx] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentView, setCurrentView] = useState<ViewType>('hub');
  const [activeTab, setActiveTab] = useState<'study' | 'source' | 'lexicon' | 'ai'>('study');
  const [isLoading, setIsLoading] = useState(true);
  const [selectedChar, setSelectedChar] = useState<string | null>(null);
  const [aiInsight, setAiInsight] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [showPinyin, setShowPinyin] = useState(true);
  const [isVertical, setIsVertical] = useState(true);
  const [stats, setStats] = useState({ learned: 124, streak: 5, points: 850 });

  const scrollRef = useRef<HTMLDivElement>(null);
  const verseRefs = useRef<(HTMLDivElement | null)[]>([]);

  // 语音播报
  const speak = (text: string, rate: number = 0.8) => {
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'zh-CN';
    utterance.rate = rate;
    window.speechSynthesis.speak(utterance);
  };

  const fetchData = useCallback(async () => {
    if (!sql) return;
    setIsLoading(true);
    try {
      const data = await sql`SELECT * FROM sanzijing_verses ORDER BY verse_index ASC`;
      if (data && data.length > 0) {
        const formatted = data.map(d => ({
          ...d,
          content_chars: Array.isArray(d.content_chars) ? d.content_chars : [],
          content_pinyin: Array.isArray(d.content_pinyin) ? d.content_pinyin : [],
          key_vocabulary: Array.isArray(d.key_vocabulary) ? d.key_vocabulary : [],
          tags: Array.isArray(d.tags) ? d.tags : [],
          char_analysis: typeof d.char_analysis === 'string' ? JSON.parse(d.char_analysis) : d.char_analysis
        })) as SanZiJingVerse[];
        setVerses(formatted);
      }
    } catch (e) {
      console.error("Fetch Error:", e);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  const fetchAiInsight = async (verse: SanZiJingVerse) => {
    if (isAiLoading || !verse) return;
    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `你是一位温和的国学老师。请针对这段经文：“${verse.content_raw}”，给孩子写一段简短、有趣的生活建议。100字以内。`,
      });
      setAiInsight(response.text || '智慧正在生成中...');
    } catch (e) {
      setAiInsight('AI 老师去休息啦，待会再试吧。');
    } finally {
      setIsAiLoading(false);
    }
  };

  useEffect(() => {
    if (activeTab === 'ai' && !aiInsight && verses[currentIdx]) {
      fetchAiInsight(verses[currentIdx]);
    }
  }, [activeTab, currentIdx, verses]);

  const playVerseSequence = useCallback((idx: number) => {
    if (!window.speechSynthesis || !verses[idx]) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(verses[idx].content_raw);
    utterance.lang = 'zh-CN';
    utterance.rate = 0.75;

    utterance.onboundary = (e) => {
      const textBefore = verses[idx].content_raw.substring(0, e.charIndex);
      const chineseOnlyBefore = textBefore.replace(/[^\u4e00-\u9fa5]/g, '');
      setCurrentCharIdx(chineseOnlyBefore.length);
    };

    utterance.onend = () => {
      setCurrentCharIdx(-1);
      if (isPlaying && idx < verses.length - 1) {
        setTimeout(() => {
           if(isPlaying) setCurrentIdx(idx + 1);
        }, 800);
      } else {
        setIsPlaying(false);
      }
    };
    window.speechSynthesis.speak(utterance);
  }, [isPlaying, verses]);

  useEffect(() => {
    if (isPlaying) playVerseSequence(currentIdx);
    verseRefs.current[currentIdx]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    setAiInsight('');
  }, [currentIdx, isPlaying, playVerseSequence]);

  const activeVerse = verses[currentIdx];

  const handleCharClick = (char: string) => {
    setSelectedChar(char);
    setActiveTab('lexicon');
    speak(char, 0.6);
  };

  // --- 视图渲染逻辑 ---

  const HubView = () => {
    const dailyIdx = useMemo(() => new Date().getDate() % (verses.length || 1), []);
    const dailyVerse = verses[dailyIdx];

    return (
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex-1 flex flex-col p-6 md:p-12 overflow-y-auto no-scrollbar">
        <div className="flex justify-between items-start mb-12">
          <div>
             <h2 className="text-3xl md:text-5xl font-black text-[#1A1A1A] serif-font mb-2">三字经 · 国学馆</h2>
             <p className="text-slate-400 font-bold tracking-[0.2em] text-xs">温故而知新，可以为师矣。</p>
          </div>
          <div className="flex items-center gap-4">
             <div className="bg-white px-4 py-2 rounded-2xl border border-[#e0d7c6] shadow-sm flex items-center gap-2">
                <Trophy size={16} className="text-[#B22222]" />
                <span className="text-xs font-black text-[#1A1A1A]">{stats.points} 积分</span>
             </div>
             <button onClick={onClose} className="p-3 bg-white border border-[#e0d7c6] rounded-2xl text-slate-400 hover:text-[#B22222] transition-all"><X size={20}/></button>
          </div>
        </div>

        <div className="relative mb-12 group cursor-pointer" onClick={() => { setCurrentIdx(dailyIdx); setCurrentView('reader'); }}>
          <div className="absolute inset-0 bg-[#B22222]/5 rounded-[3rem] blur-3xl opacity-50 group-hover:opacity-100 transition-opacity" />
          <div className="relative bg-white/90 backdrop-blur-xl border border-[#e0d7c6] rounded-[2.5rem] md:rounded-[4rem] p-10 md:p-20 shadow-xl overflow-hidden">
             <div className="flex flex-col md:flex-row items-center gap-8 md:gap-16">
                <div className="flex flex-col items-center">
                   <div className="text-[10px] font-black text-[#B22222] bg-[#B22222]/10 px-3 py-1 rounded-full mb-6 tracking-widest uppercase">Daily Wisdom</div>
                   <div className="text-8xl md:text-9xl font-black text-[#1A1A1A] tracking-tighter serif-font leading-none">{dailyVerse?.content_chars.slice(0, 3).join('')}</div>
                </div>
                <div className="flex-1 text-center md:text-left">
                   <p className="text-xl md:text-3xl text-slate-600 leading-relaxed font-bold italic mb-8 serif-font">“{dailyVerse?.translation_vernacular}”</p>
                   <button className="px-10 py-4 bg-[#B22222] text-white rounded-full text-xs font-black uppercase tracking-widest hover:bg-[#1A1A1A] transition-all flex items-center gap-3 shadow-xl">开始修行 <ChevronRight size={18} /></button>
                </div>
             </div>
          </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
           <HubCard icon={<BookOpen size={24}/>} label="全息长卷" sub="Full Content" onClick={() => setCurrentView('reader')} />
           <HubCard icon={<Compass size={24}/>} label="典故寻踪" sub="Story Finder" onClick={() => setCurrentView('stories')} />
           <HubCard icon={<History size={24}/>} label="复习巩固" sub="Recent Review" onClick={() => setCurrentView('reader')} />
           <HubCard icon={<Sparkles size={24}/>} label="AI 陪读" sub="AI Companion" onClick={() => { setCurrentView('reader'); setActiveTab('ai'); }} />
        </div>
      </motion.div>
    );
  };

  const ReaderView = () => (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex-1 flex flex-col lg:flex-row overflow-hidden bg-[#FDFBF7]">
      {/* 核心阅读区 */}
      <section className="flex-1 flex flex-col min-h-0 relative">
        {/* 顶部控制栏 (按照原型图设计) */}
        <div className="h-20 flex items-center justify-between px-8 bg-white/80 backdrop-blur-xl border-b border-[#e0d7c6] z-40 shrink-0">
           <button onClick={() => setCurrentView('hub')} className="p-3 bg-white border border-[#e0d7c6] rounded-2xl text-slate-400 hover:text-[#B22222] shadow-sm"><ArrowLeft size={20} /></button>

           <div className="flex items-center gap-3 bg-[#1A1A1A] p-2 rounded-full shadow-2xl">
              <button onClick={() => setCurrentIdx(prev => Math.max(0, prev - 1))} className="p-2.5 text-white/50 hover:text-white"><SkipBack size={20} fill="currentColor"/></button>
              <button onClick={() => setIsPlaying(!isPlaying)} className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-lg active:scale-90 transition-all">
                 {isPlaying ? <Pause size={24} className="text-[#1A1A1A]" fill="currentColor"/> : <Play size={24} className="text-[#1A1A1A] ml-1" fill="currentColor"/>}
              </button>
              <button onClick={() => setCurrentIdx(prev => Math.min(verses.length - 1, prev + 1))} className="p-2.5 text-white/50 hover:text-white"><SkipForward size={20} fill="currentColor"/></button>
           </div>

           <div className="flex gap-2">
              <ReaderAction icon={<Type size={18}/>} active={showPinyin} onClick={() => setShowPinyin(!showPinyin)} />
              <ReaderAction icon={<LayoutGrid size={18}/>} active={isVertical} onClick={() => setIsVertical(!isVertical)} />
              <button className="p-3 bg-[#B22222] text-white rounded-2xl shadow-lg shadow-[#B22222]/20"><Menu size={20}/></button>
           </div>
        </div>

        <div className="flex-1 overflow-y-auto no-scrollbar scroll-smooth p-8 md:p-16">
          <div className="max-w-4xl mx-auto space-y-32">
            {verses.map((v, i) => (
              <div 
                key={v.id} ref={el => { verseRefs.current[i] = el; }}
                className={`transition-all duration-700 cursor-pointer flex justify-center ${currentIdx === i ? 'opacity-100 scale-100' : 'opacity-10 scale-95 blur-[1px]'}`}
                onClick={() => { setCurrentIdx(i); setIsPlaying(false); }}
              >
                <div className={`flex ${isVertical ? 'flex-row-reverse' : 'flex-col'} items-center gap-12 py-16 px-16 border-x border-[#B22222]/10 relative group`}>
                   <div className="absolute top-0 left-0 w-full h-px bg-gradient-to-r from-transparent via-[#B22222]/20 to-transparent" />
                   <div className="absolute bottom-0 left-0 w-full h-px bg-gradient-to-r from-transparent via-[#B22222]/20 to-transparent" />

                   <div className="flex flex-wrap justify-center gap-x-16 md:gap-x-24 gap-y-12 max-w-[600px]">
                      {v.content_chars.map((char, cIdx) => (
                        <div 
                          key={cIdx} 
                          onClick={(e) => { e.stopPropagation(); handleCharClick(char); }}
                          className="flex flex-col items-center group/char"
                        >
                           {showPinyin && (
                             <span className={`text-[11px] md:text-sm font-mono mb-4 transition-colors ${currentIdx === i && currentCharIdx === cIdx ? 'text-[#B22222] font-black' : 'text-slate-300'}`}>
                               {v.content_pinyin[cIdx]}
                             </span>
                           )}
                           <span className={`text-7xl md:text-[10rem] font-black leading-none serif-font transition-all ${currentIdx === i && currentCharIdx === cIdx ? 'text-[#1A1A1A] drop-shadow-2xl scale-110' : 'text-slate-200 group-hover/char:text-slate-400'}`}>
                             {char}
                           </span>
                        </div>
                      ))}
                   </div>
                </div>
              </div>
            ))}
          </div>
          <div className="h-96" />
        </div>
      </section>

      {/* 右侧解析面板 (深度还原原型) */}
      <aside className="lg:w-[480px] xl:w-[540px] flex flex-col bg-white border-l border-[#e0d7c6] shadow-[-40px_0_100px_rgba(0,0,0,0.02)] z-30">
        <nav className="flex bg-[#FDFBF7] border-b border-[#e0d7c6] shrink-0">
          {[
            { id: 'study', icon: <BookOpen size={16}/>, label: '义理' },
            { id: 'source', icon: <History size={16}/>, label: '典故' },
            { id: 'lexicon', icon: <Search size={16}/>, label: '字解' },
            { id: 'ai', icon: <Sparkles size={16}/>, label: 'AI' }
          ].map((tab: any) => (
            <button
              key={tab.id} onClick={() => setActiveTab(tab.id)}
              className={`flex-1 py-8 flex flex-col items-center gap-2 text-[11px] font-black transition-all relative ${activeTab === tab.id ? 'text-[#B22222] bg-white' : 'text-slate-400 hover:bg-slate-50'}`}
            >
              {tab.icon} {tab.label}
              {activeTab === tab.id && <motion.div layoutId="tab-underline" className="absolute bottom-0 w-full h-1.5 bg-[#B22222]" />}
            </button>
          ))}
        </nav>

        <div className="flex-1 overflow-y-auto p-10 md:p-14 no-scrollbar">
          <AnimatePresence mode="wait">
             {activeTab === 'study' && (
               <motion.div key="study" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }} className="space-y-12">
                  <section>
                    <h4 className="text-[10px] font-black text-slate-300 uppercase tracking-widest mb-6 serif-font italic">现代译文</h4>
                    <p className="text-3xl md:text-4xl font-black text-[#1A1A1A] leading-tight italic serif-font">“{activeVerse?.translation_vernacular}”</p>
                  </section>
                  <section className="bg-[#F9F6F0] p-10 rounded-[2.5rem] border border-[#e0d7c6] shadow-inner">
                    <h4 className="text-[10px] font-black text-[#B22222] uppercase tracking-[0.4em] mb-8 flex items-center gap-2">深度导读</h4>
                    <p className="text-lg md:text-xl text-slate-600 leading-relaxed font-medium text-justify">{activeVerse?.interpretation_deep}</p>
                  </section>
               </motion.div>
             )}

             {activeTab === 'source' && (
               <motion.div key="source" initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="space-y-10">
                  {activeVerse?.allusion_title ? (
                    <div className="space-y-8">
                       <div className="inline-block px-4 py-1.5 bg-[#B22222]/5 text-[#B22222] rounded-full text-[10px] font-black">{activeVerse.allusion_source}</div>
                       <h3 className="text-4xl font-black serif-font text-[#1A1A1A]">{activeVerse.allusion_title}</h3>
                       <div className="p-8 bg-white border-2 border-dashed border-[#e0d7c6] rounded-[2rem]">
                          <p className="text-lg text-slate-500 leading-loose italic">{activeVerse.allusion_context}</p>
                       </div>
                    </div>
                  ) : (
                    <div className="py-20 text-center opacity-30">
                       <Compass size={64} className="mx-auto mb-6" />
                       <p className="serif-font font-black">此章节暂未收录典故</p>
                    </div>
                  )}
               </motion.div>
             )}

             {activeTab === 'lexicon' && (
               <motion.div key="lexicon" initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-12">
                  <div className="flex items-center gap-4 p-4 bg-slate-50 rounded-2xl border border-slate-100 mb-8">
                    <Info size={16} className="text-[#B22222]" />
                    <p className="text-[10px] font-bold text-slate-400">提示：点击左侧经文中的汉字，即可查看精细解读。</p>
                  </div>

                  {selectedChar && activeVerse?.char_analysis[selectedChar] ? (
                    <div className="space-y-10">
                       <div className="flex items-end gap-6 border-b border-[#f3efe6] pb-8">
                          <div className="text-8xl font-black text-[#1A1A1A] serif-font leading-none">{selectedChar}</div>
                          <div className="pb-2">
                             <div className="text-2xl font-mono font-black text-[#B22222]">{activeVerse.char_analysis[selectedChar].pinyin}</div>
                             <div className="text-[10px] font-black text-slate-400 tracking-widest uppercase mt-1">部首: {activeVerse.char_analysis[selectedChar].radical} | 笔画: {activeVerse.char_analysis[selectedChar].strokes}</div>
                          </div>
                       </div>
                       <section className="grid grid-cols-2 gap-4">
                          <div className="p-6 bg-slate-50 rounded-2xl">
                             <h5 className="text-[9px] font-black text-slate-400 uppercase mb-3">字形构造</h5>
                             <div className="text-lg font-black text-[#1A1A1A]">{activeVerse.char_analysis[selectedChar].formation}</div>
                          </div>
                          <div className="p-6 bg-slate-50 rounded-2xl">
                             <h5 className="text-[9px] font-black text-slate-400 uppercase mb-3">本义探源</h5>
                             <div className="text-lg font-black text-[#1A1A1A]">{activeVerse.char_analysis[selectedChar].original_meaning}</div>
                          </div>
                       </section>
                       <section>
                          <h5 className="text-[10px] font-black text-[#B22222] uppercase mb-4 flex items-center gap-2"><Sparkles size={12}/> 字理演变</h5>
                          <p className="text-lg text-slate-600 leading-relaxed font-medium italic">{activeVerse.char_analysis[selectedChar].evolution_story}</p>
                       </section>
                    </div>
                  ) : (
                    <div className="py-32 flex flex-col items-center justify-center opacity-10">
                       <Type size={120} className="text-slate-900 mb-8" />
                       <p className="text-2xl font-black serif-font">点击字符以解析</p>
                    </div>
                  )}
               </motion.div>
             )}

             {activeTab === 'ai' && (
                <motion.div key="ai" initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-12">
                   <div className="p-10 bg-emerald-50/50 border border-emerald-100 rounded-[3.5rem] relative overflow-hidden">
                      <div className="flex items-center justify-between mb-10 text-emerald-600">
                        <div className="flex items-center gap-3"><Mic2 size={24} /> <h4 className="text-[10px] font-black uppercase tracking-[0.4em]">AI 伴读智慧</h4></div>
                        {isAiLoading && <Loader2 size={20} className="animate-spin" />}
                      </div>

                      {isAiLoading ? (
                        <div className="py-20 flex flex-col items-center gap-6">
                          <p className="text-[11px] text-emerald-400 font-black tracking-[0.3em] animate-pulse">正在感悟经文义理...</p>
                        </div>
                      ) : (
                        <div className="animate-in fade-in duration-1000">
                           <p className="text-3xl font-bold text-emerald-900 leading-snug italic mb-12 serif-font">“{aiInsight}”</p>
                           <div className="bg-emerald-900 text-white p-8 rounded-3xl flex items-center gap-6 shadow-2xl">
                              <Target size={32} className="text-emerald-300 shrink-0" />
                              <p className="text-sm font-medium leading-relaxed opacity-90 italic">这是为你准备的学习建议，愿你在生活中践行经文教诲。</p>
                           </div>
                        </div>
                      )}
                   </div>
                   <button 
                    onClick={() => activeVerse && fetchAiInsight(activeVerse)}
                    className="w-full py-5 bg-white border-2 border-emerald-100 text-emerald-600 rounded-3xl font-black flex items-center justify-center gap-3 hover:bg-emerald-50 transition-all active:scale-95"
                   >
                     <RefreshCw size={18} /> 换一个角度解析
                   </button>
                </motion.div>
             )}
          </AnimatePresence>
        </div>
      </aside>
    </motion.div>
  );

  return (
    <div className="fixed inset-0 z-[60] bg-[#FDFBF7] flex flex-col select-none overflow-hidden pb-[env(safe-area-inset-bottom)]">
      <div className="absolute inset-0 opacity-[0.06] pointer-events-none z-0 bg-[url('https://www.transparenttextures.com/patterns/rice-paper.png')]" />

      {isLoading ? (
        <div className="flex-1 flex flex-col items-center justify-center bg-[#FDFBF7]">
           <div className="relative mb-8">
              <div className="w-24 h-24 bg-[#B22222]/10 rounded-full animate-ping opacity-30" />
              <div className="absolute inset-0 m-auto w-12 h-12 border-4 border-[#B22222] border-t-transparent rounded-full animate-spin" />
           </div>
           <p className="text-xs font-black tracking-[0.5em] text-[#B22222] uppercase animate-pulse">正在开启全息经文长卷...</p>
        </div>
      ) : (
        <AnimatePresence mode="wait">
          {currentView === 'hub' ? <HubView /> : <ReaderView />}
        </AnimatePresence>
      )}

      {/* 底部页脚 */}
      <footer className="h-10 bg-white/60 border-t border-[#e0d7c6] px-8 flex items-center justify-between z-40 text-[9px] font-bold text-slate-400 italic">
         <div className="flex gap-10">
           <span className="flex items-center gap-1.5"><span className="w-1.5 h-1.5 bg-[#B22222] rounded-full animate-pulse"></span> 传承模式: 核心同步中</span>
           <span className="uppercase tracking-widest hidden sm:inline">Records_Version: 3.1.2_Stable</span>
         </div>
         <div className="flex gap-6">
            <span className="flex items-center gap-1"><Languages size={10}/> 语言: 简体中文 / Pinyin</span>
         </div>
      </footer>

      <style>{`
        .serif-font { font-family: 'Noto Serif SC', serif; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .rotate-y-180 { transform: rotateY(180deg); }
      `}</style>
    </div>
  );
};

const HubCard = ({ icon, label, sub, onClick }: any) => (
  <button onClick={onClick} className="bg-white border border-[#e0d7c6] p-8 rounded-[2.5rem] flex flex-col items-center gap-4 hover:border-[#B22222] hover:shadow-xl transition-all group shadow-sm">
     <div className="w-16 h-16 bg-[#F9F6F0] rounded-2xl flex items-center justify-center text-slate-400 group-hover:text-[#B22222] transition-colors shadow-inner">
       {icon}
     </div>
     <div className="text-center">
        <div className="text-lg font-black text-[#1A1A1A] serif-font">{label}</div>
        <div className="text-[8px] font-bold text-slate-300 uppercase tracking-widest mt-1">{sub}</div>
     </div>
  </button>
);

const ReaderAction = ({ icon, active, onClick }: any) => (
  <button onClick={onClick} className={`p-3 rounded-2xl transition-all border ${active ? 'bg-[#1A1A1A] border-[#1A1A1A] text-white shadow-lg' : 'bg-white border-[#e0d7c6] text-slate-300'}`}>
    {icon}
  </button>
);

const StoriesView = () => (
   <div className="p-12">
     <h2 className="text-4xl font-black serif-font text-slate-900 mb-12">典故全集</h2>
     <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {/* 此处可根据数据列表渲染更多卡片 */}
     </div>
   </div>
);

const ProfileView = () => (
   <div className="p-12">
     <h2 className="text-4xl font-black serif-font text-slate-900 mb-12">修行印记</h2>
     <div className="grid grid-cols-3 gap-6">
        <div className="bg-white p-8 rounded-3xl border border-[#e0d7c6] text-center">
           <div className="text-4xl font-black text-[#B22222] mb-2">124</div>
           <div className="text-xs text-slate-400">已学字符</div>
        </div>
     </div>
   </div>
);

export default ThreeCharacterApp;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  X, Play, Pause, ScrollText, ChevronRight, Sparkles, 
  RefreshCw, BookOpen, Volume2, SkipBack, SkipForward, 
  ArrowLeft, Search, Bookmark, History, LayoutGrid, 
  Library, Trophy, Target, Type, Mic2, FileText, 
  Compass, Feather, User, Menu, Sliders, Loader2, Star,
  Info, ChevronDown, ChevronUp, Languages
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { SanZiJingVerse, CharAnalysis } from '../lib/sanzijingData';
import { GoogleGenAI } from "@google/genai";
import sql from '../lib/neon';

type ViewType = 'hub' | 'reader' | 'stories' | 'profile';

const ThreeCharacterApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [verses, setVerses] = useState<SanZiJingVerse[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [currentCharIdx, setCurrentCharIdx] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentView, setCurrentView] = useState<ViewType>('hub');
  const [activeTab, setActiveTab] = useState<'study' | 'source' | 'lexicon' | 'ai'>('study');
  const [isLoading, setIsLoading] = useState(true);
  const [selectedChar, setSelectedChar] = useState<string | null>(null);
  const [aiInsight, setAiInsight] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [showPinyin, setShowPinyin] = useState(true);
  const [isVertical, setIsVertical] = useState(true);
  const [stats, setStats] = useState({ learned: 124, streak: 5, points: 850 });

  const scrollRef = useRef<HTMLDivElement>(null);
  const verseRefs = useRef<(HTMLDivElement | null)[]>([]);

  // 语音播报
  const speak = (text: string, rate: number = 0.8) => {
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'zh-CN';
    utterance.rate = rate;
    window.speechSynthesis.speak(utterance);
  };

  const fetchData = useCallback(async () => {
    if (!sql) return;
    setIsLoading(true);
    try {
      const data = await sql`SELECT * FROM sanzijing_verses ORDER BY verse_index ASC`;
      if (data && data.length > 0) {
        const formatted = data.map(d => ({
          ...d,
          content_chars: Array.isArray(d.content_chars) ? d.content_chars : [],
          content_pinyin: Array.isArray(d.content_pinyin) ? d.content_pinyin : [],
          key_vocabulary: Array.isArray(d.key_vocabulary) ? d.key_vocabulary : [],
          tags: Array.isArray(d.tags) ? d.tags : [],
          char_analysis: typeof d.char_analysis === 'string' ? JSON.parse(d.char_analysis) : d.char_analysis
        })) as SanZiJingVerse[];
        setVerses(formatted);
      }
    } catch (e) {
      console.error("Fetch Error:", e);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  const fetchAiInsight = async (verse: SanZiJingVerse) => {
    if (isAiLoading || !verse) return;
    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `你是一位温和的国学老师。请针对这段经文：“${verse.content_raw}”，给孩子写一段简短、有趣的生活建议。100字以内。`,
      });
      setAiInsight(response.text || '智慧正在生成中...');
    } catch (e) {
      setAiInsight('AI 老师去休息啦，待会再试吧。');
    } finally {
      setIsAiLoading(false);
    }
  };

  useEffect(() => {
    if (activeTab === 'ai' && !aiInsight && verses[currentIdx]) {
      fetchAiInsight(verses[currentIdx]);
    }
  }, [activeTab, currentIdx, verses]);

  const playVerseSequence = useCallback((idx: number) => {
    if (!window.speechSynthesis || !verses[idx]) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(verses[idx].content_raw);
    utterance.lang = 'zh-CN';
    utterance.rate = 0.75;

    utterance.onboundary = (e) => {
      const textBefore = verses[idx].content_raw.substring(0, e.charIndex);
      const chineseOnlyBefore = textBefore.replace(/[^\u4e00-\u9fa5]/g, '');
      setCurrentCharIdx(chineseOnlyBefore.length);
    };

    utterance.onend = () => {
      setCurrentCharIdx(-1);
      if (isPlaying && idx < verses.length - 1) {
        setTimeout(() => {
           if(isPlaying) setCurrentIdx(idx + 1);
        }, 800);
      } else {
        setIsPlaying(false);
      }
    };
    window.speechSynthesis.speak(utterance);
  }, [isPlaying, verses]);

  useEffect(() => {
    if (isPlaying) playVerseSequence(currentIdx);
    verseRefs.current[currentIdx]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    setAiInsight('');
  }, [currentIdx, isPlaying, playVerseSequence]);

  const activeVerse = verses[currentIdx];

  const handleCharClick = (char: string) => {
    setSelectedChar(char);
    setActiveTab('lexicon');
    speak(char, 0.6);
  };

  // --- 视图渲染 ---

  const HubView = () => {
    const dailyIdx = useMemo(() => new Date().getDate() % (verses.length || 1), []);
    const dailyVerse = verses[dailyIdx];

    return (
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex-1 flex flex-col p-6 md:p-12 overflow-y-auto no-scrollbar">
        <div className="flex justify-between items-start mb-12">
          <div>
             <h2 className="text-3xl md:text-5xl font-black text-[#1A1A1A] serif-font mb-2">三字经 · 国学馆</h2>
             <p className="text-slate-400 font-bold tracking-[0.2em] text-xs">温故而知新，可以为师矣。</p>
          </div>
          <div className="flex items-center gap-4">
             <div className="bg-white px-4 py-2 rounded-2xl border border-[#e0d7c6] shadow-sm flex items-center gap-2">
                <Trophy size={16} className="text-[#B22222]" />
                <span className="text-xs font-black text-[#1A1A1A]">{stats.points} 积分</span>
             </div>
             <button onClick={onClose} className="p-3 bg-white border border-[#e0d7c6] rounded-2xl text-slate-400 hover:text-[#B22222] transition-all"><X size={20}/></button>
          </div>
        </div>

        <div className="relative mb-12 group cursor-pointer" onClick={() => { setCurrentIdx(dailyIdx); setCurrentView('reader'); }}>
          <div className="absolute inset-0 bg-[#B22222]/5 rounded-[3rem] blur-3xl opacity-50 group-hover:opacity-100 transition-opacity" />
          <div className="relative bg-white/90 backdrop-blur-xl border border-[#e0d7c6] rounded-[2.5rem] md:rounded-[4rem] p-10 md:p-20 shadow-xl overflow-hidden">
             <div className="flex flex-col md:flex-row items-center gap-8 md:gap-16">
                <div className="flex flex-col items-center">
                   <div className="text-[10px] font-black text-[#B22222] bg-[#B22222]/10 px-3 py-1 rounded-full mb-6 tracking-widest uppercase">Daily Wisdom</div>
                   <div className="text-8xl md:text-9xl font-black text-[#1A1A1A] tracking-tighter serif-font leading-none">{dailyVerse?.content_chars.slice(0, 3).join('')}</div>
                </div>
                <div className="flex-1 text-center md:text-left">
                   <p className="text-xl md:text-3xl text-slate-600 leading-relaxed font-bold italic mb-8 serif-font">“{dailyVerse?.translation_vernacular}”</p>
                   <button className="px-10 py-4 bg-[#B22222] text-white rounded-full text-xs font-black uppercase tracking-widest hover:bg-[#1A1A1A] transition-all flex items-center gap-3 shadow-xl">开始修行 <ChevronRight size={18} /></button>
                </div>
             </div>
          </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
           <HubCard icon={<BookOpen size={24}/>} label="全息长卷" sub="Full Content" onClick={() => setCurrentView('reader')} />
           <HubCard icon={<Compass size={24}/>} label="典故寻踪" sub="Story Finder" onClick={() => setCurrentView('stories')} />
           <HubCard icon={<History size={24}/>} label="复习巩固" sub="Recent Review" onClick={() => setCurrentView('reader')} />
           <HubCard icon={<Sparkles size={24}/>} label="AI 陪读" sub="AI Companion" onClick={() => { setCurrentView('reader'); setActiveTab('ai'); }} />
        </div>
      </motion.div>
    );
  };

  const ReaderView = () => (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex-1 flex flex-col overflow-hidden bg-[#FDFBF7]">

      {/* 顶部控制栏 - 还原原型图设计 */}
      <header className="fixed top-0 left-0 w-full z-50 px-4 md:px-8 py-4 pointer-events-none">
        <div className="max-w-7xl mx-auto flex items-center justify-between pointer-events-auto">
           {/* 返回按钮 */}
           <button onClick={() => setCurrentView('hub')} className="p-3 bg-white border border-[#e0d7c6] rounded-2xl text-slate-400 hover:text-[#B22222] shadow-xl transition-all active:scale-95">
             <ArrowLeft size={24} />
           </button>

           {/* 播放控制组 (深色胶囊) */}
           <div className="flex items-center gap-2 bg-[#1A1A1A] p-2 rounded-full shadow-2xl">
              <button onClick={() => setCurrentIdx(prev => Math.max(0, prev - 1))} className="p-2.5 text-white/40 hover:text-white transition-colors">
                <SkipBack size={20} fill="currentColor"/>
              </button>
              <button onClick={() => setIsPlaying(!isPlaying)} className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-lg active:scale-90 transition-all">
                 {isPlaying ? <Pause size={24} className="text-[#1A1A1A]" fill="currentColor"/> : <Play size={24} className="text-[#1A1A1A] ml-1" fill="currentColor"/>}
              </button>
              <button onClick={() => setCurrentIdx(prev => Math.min(verses.length - 1, prev + 1))} className="p-2.5 text-white/40 hover:text-white transition-colors">
                <SkipForward size={20} fill="currentColor"/>
              </button>
           </div>

           {/* 功能切换组 */}
           <div className="flex gap-2">
              <ReaderAction icon={<Type size={18}/>} active={showPinyin} onClick={() => setShowPinyin(!showPinyin)} />
              <ReaderAction icon={<LayoutGrid size={18}/>} active={isVertical} onClick={() => setIsVertical(!isVertical)} />
              <button className="p-3 bg-[#B22222] text-white rounded-2xl shadow-xl shadow-[#B22222]/20 active:scale-95">
                <Menu size={20}/>
              </button>
           </div>
        </div>
      </header>

      {/* 阅读器主容器 - 左右分栏 */}
      <div className="flex-1 flex flex-col lg:flex-row overflow-hidden">

        {/* 左侧：经文原文展示区 */}
        <section className="flex-1 overflow-y-auto no-scrollbar scroll-smooth relative pt-32 pb-40">
           <div className="max-w-4xl mx-auto space-y-48">
              {verses.map((v, i) => (
                <div 
                  key={v.id} ref={el => { verseRefs.current[i] = el; }}
                  className={`transition-all duration-1000 cursor-pointer flex justify-center ${currentIdx === i ? 'opacity-100 scale-110' : 'opacity-10 scale-90 blur-[1px]'}`}
                  onClick={() => { setCurrentIdx(i); setIsPlaying(false); }}
                >
                  <div className={`flex ${isVertical ? 'flex-row-reverse' : 'flex-col'} items-center gap-12 py-12 px-12 relative group`}>
                    <div className="absolute top-0 left-0 w-full h-px bg-gradient-to-r from-transparent via-[#B22222]/20 to-transparent" />
                    <div className="absolute bottom-0 left-0 w-full h-px bg-gradient-to-r from-transparent via-[#B22222]/20 to-transparent" />

                    <div className="flex flex-wrap justify-center gap-x-12 md:gap-x-20 gap-y-12 max-w-[600px]">
                        {v.content_chars.map((char, cIdx) => (
                          <div 
                            key={cIdx} 
                            onClick={(e) => { e.stopPropagation(); handleCharClick(char); }}
                            className="flex flex-col items-center group/char"
                          >
                            {showPinyin && (
                              <span className={`text-[11px] md:text-sm font-mono mb-4 transition-colors ${currentIdx === i && currentCharIdx === cIdx ? 'text-[#B22222] font-black' : 'text-slate-300'}`}>
                                {v.content_pinyin[cIdx]}
                              </span>
                            )}
                            <span className={`text-7xl md:text-[9rem] font-black leading-none serif-font transition-all ${currentIdx === i && currentCharIdx === cIdx ? 'text-[#1A1A1A] drop-shadow-2xl' : 'text-slate-200 group-hover/char:text-slate-400'}`}>
                              {char}
                            </span>
                          </div>
                        ))}
                    </div>
                  </div>
                </div>
              ))}
           </div>
           <div className="h-96" />
        </section>

        {/* 右侧：功能解析面板 (还原原型图 Tabs) */}
        <aside className="lg:w-[480px] xl:w-[520px] flex flex-col bg-white border-l border-[#e0d7c6] shadow-[-40px_0_100px_rgba(0,0,0,0.02)] z-40 relative">
          {/* 选项卡导航 */}
          <nav className="flex bg-[#FDFBF7] border-b border-[#e0d7c6] shrink-0 pt-2 lg:pt-0">
            {[
              { id: 'study', icon: <BookOpen size={16}/>, label: '义理' },
              { id: 'source', icon: <History size={16}/>, label: '典故' },
              { id: 'lexicon', icon: <Search size={16}/>, label: '字解' },
              { id: 'ai', icon: <Sparkles size={16}/>, label: 'AI' }
            ].map((tab: any) => (
              <button
                key={tab.id} onClick={() => setActiveTab(tab.id)}
                className={`flex-1 py-8 flex flex-col items-center gap-2 text-[11px] font-black transition-all relative ${activeTab === tab.id ? 'text-[#B22222] bg-white' : 'text-slate-400 hover:bg-slate-50'}`}
              >
                {tab.icon} {tab.label}
                {activeTab === tab.id && <motion.div layoutId="tab-underline" className="absolute bottom-0 w-full h-1.5 bg-[#B22222]" />}
              </button>
            ))}
          </nav>

          {/* 解析内容区 */}
          <div className="flex-1 overflow-y-auto p-8 md:p-12 no-scrollbar">
            <AnimatePresence mode="wait">
               {activeTab === 'study' && (
                 <motion.div key="study" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -10 }} className="space-y-12">
                    <section>
                      <h4 className="text-[10px] font-black text-slate-300 uppercase tracking-widest mb-6 serif-font italic">现代译文</h4>
                      <p className="text-3xl md:text-4xl font-black text-[#1A1A1A] leading-tight italic serif-font">“{activeVerse?.translation_vernacular}”</p>
                    </section>
                    <section className="bg-[#F9F6F0] p-8 md:p-10 rounded-[2.5rem] border border-[#e0d7c6] shadow-inner">
                      <h4 className="text-[10px] font-black text-[#B22222] uppercase tracking-[0.4em] mb-8 flex items-center gap-2">深度导读</h4>
                      <p className="text-lg md:text-xl text-slate-600 leading-relaxed font-medium text-justify">{activeVerse?.interpretation_deep}</p>
                    </section>
                 </motion.div>
               )}

               {activeTab === 'source' && (
                 <motion.div key="source" initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-10">
                    {activeVerse?.allusion_title ? (
                      <div className="space-y-8">
                         <div className="inline-block px-4 py-1.5 bg-[#B22222]/5 text-[#B22222] rounded-full text-[10px] font-black">{activeVerse.allusion_source}</div>
                         <h3 className="text-4xl font-black serif-font text-[#1A1A1A]">{activeVerse.allusion_title}</h3>
                         <div className="p-8 bg-white border-2 border-dashed border-[#e0d7c6] rounded-[2rem]">
                            <p className="text-lg text-slate-500 leading-loose italic">{activeVerse.allusion_context}</p>
                         </div>
                      </div>
                    ) : (
                      <div className="py-20 text-center opacity-30">
                         <Compass size={64} className="mx-auto mb-6" />
                         <p className="serif-font font-black">此章节暂未收录典故</p>
                      </div>
                    )}
                 </motion.div>
               )}

               {activeTab === 'lexicon' && (
                 <motion.div key="lexicon" initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-12">
                    <div className="flex items-center gap-4 p-4 bg-slate-50 rounded-2xl border border-slate-100 mb-8">
                      <Info size={16} className="text-[#B22222]" />
                      <p className="text-[10px] font-bold text-slate-400">提示：点击左侧原文汉字，查看精细字解。</p>
                    </div>

                    {selectedChar && activeVerse?.char_analysis[selectedChar] ? (
                      <div className="space-y-10">
                         <div className="flex items-end gap-6 border-b border-[#f3efe6] pb-8">
                            <div className="text-8xl font-black text-[#1A1A1A] serif-font leading-none">{selectedChar}</div>
                            <div className="pb-2">
                               <div className="text-2xl font-mono font-black text-[#B22222]">{activeVerse.char_analysis[selectedChar].pinyin}</div>
                               <div className="text-[10px] font-black text-slate-400 tracking-widest uppercase mt-1">部首: {activeVerse.char_analysis[selectedChar].radical} | 笔画: {activeVerse.char_analysis[selectedChar].strokes}</div>
                            </div>
                         </div>
                         <section className="grid grid-cols-2 gap-4">
                            <div className="p-6 bg-slate-50 rounded-2xl">
                               <h5 className="text-[9px] font-black text-slate-400 uppercase mb-3">字形构造</h5>
                               <div className="text-lg font-black text-[#1A1A1A]">{activeVerse.char_analysis[selectedChar].formation}</div>
                            </div>
                            <div className="p-6 bg-slate-50 rounded-2xl">
                               <h5 className="text-[9px] font-black text-slate-400 uppercase mb-3">本义探源</h5>
                               <div className="text-lg font-black text-[#1A1A1A]">{activeVerse.char_analysis[selectedChar].original_meaning}</div>
                            </div>
                         </section>
                         <section>
                            <h5 className="text-[10px] font-black text-[#B22222] uppercase mb-4 flex items-center gap-2"><Sparkles size={12}/> 字理演变</h5>
                            <p className="text-lg text-slate-600 leading-relaxed font-medium italic">{activeVerse.char_analysis[selectedChar].evolution_story}</p>
                         </section>
                      </div>
                    ) : (
                      <div className="py-32 flex flex-col items-center justify-center opacity-10">
                         <Type size={120} className="text-slate-900 mb-8" />
                         <p className="text-2xl font-black serif-font">点击字符以解析</p>
                      </div>
                    )}
                 </motion.div>
               )}

               {activeTab === 'ai' && (
                  <motion.div key="ai" initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-12">
                     <div className="p-10 bg-emerald-50/50 border border-emerald-100 rounded-[3.5rem] relative overflow-hidden">
                        <div className="flex items-center justify-between mb-10 text-emerald-600">
                          <div className="flex items-center gap-3"><Mic2 size={24} /> <h4 className="text-[10px] font-black uppercase tracking-[0.4em]">AI 伴读智慧</h4></div>
                          {isAiLoading && <Loader2 size={20} className="animate-spin" />}
                        </div>

                        {isAiLoading ? (
                          <div className="py-20 flex flex-col items-center gap-6">
                            <p className="text-[11px] text-emerald-400 font-black tracking-[0.3em] animate-pulse">正在感悟经文义理...</p>
                          </div>
                        ) : (
                          <div className="animate-in fade-in duration-1000">
                             <p className="text-3xl font-bold text-emerald-900 leading-snug italic mb-12 serif-font">“{aiInsight}”</p>
                             <div className="bg-emerald-900 text-white p-8 rounded-3xl flex items-center gap-6 shadow-2xl">
                                <Target size={32} className="text-emerald-300 shrink-0" />
                                <p className="text-sm font-medium leading-relaxed opacity-90 italic">这是为您准备的学习建议。</p>
                             </div>
                          </div>
                        )}
