                        {isAiLoading ? (
                          <div className="py-12 flex flex-col items-center gap-4">
                            <p className="text-[10px] text-emerald-400 font-black tracking-[0.2em] animate-pulse">正在感悟经文...</p>
                          </div>
                        ) : (
                          <div className="animate-in fade-in duration-1000">
