import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  X, Play, Pause, ScrollText, ChevronRight, Sparkles, 
  RefreshCw, BookOpen, Volume2, SkipBack, SkipForward, 
  ArrowLeft, Search, Bookmark, History, LayoutGrid, 
  Library, Trophy, Target, Type, Mic2, FileText, 
  Compass, Feather, User, Menu, Sliders, Loader2, Star,
  Info, ChevronDown, ChevronUp, Languages, Quote
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { SanZiJingVerse, CharAnalysis } from '../lib/sanzijingData';
import { GoogleGenAI } from "@google/genai";
import sql from '../lib/neon';

type ViewType = 'hub' | 'reader';

const ThreeCharacterApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [verses, setVerses] = useState<SanZiJingVerse[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [currentCharIdx, setCurrentCharIdx] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentView, setCurrentView] = useState<ViewType>('hub');
  const [activeTab, setActiveTab] = useState<'study' | 'source' | 'lexicon' | 'ai'>('study');
  const [isLoading, setIsLoading] = useState(true);
  const [selectedChar, setSelectedChar] = useState<string | null>(null);
  const [aiInsight, setAiInsight] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [showPinyin, setShowPinyin] = useState(true);
  const [stats, setStats] = useState({ learned: 124, streak: 5, points: 850 });

  const scrollRef = useRef<HTMLDivElement>(null);
  const verseRefs = useRef<(HTMLDivElement | null)[]>([]);

  const speak = (text: string, rate: number = 0.8) => {
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'zh-CN';
    utterance.rate = rate;
    window.speechSynthesis.speak(utterance);
  };

  const fetchData = useCallback(async () => {
    if (!sql) return;
    setIsLoading(true);
    try {
      const data = await sql`SELECT * FROM sanzijing_verses ORDER BY verse_index ASC`;
      if (data && data.length > 0) {
        const formatted = data.map(d => ({
          ...d,
          content_chars: Array.isArray(d.content_chars) ? d.content_chars : [],
          content_pinyin: Array.isArray(d.content_pinyin) ? d.content_pinyin : [],
          key_vocabulary: Array.isArray(d.key_vocabulary) ? d.key_vocabulary : [],
          tags: Array.isArray(d.tags) ? d.tags : [],
          char_analysis: typeof d.char_analysis === 'string' ? JSON.parse(d.char_analysis) : d.char_analysis
        })) as SanZiJingVerse[];
        setVerses(formatted);
      }
    } catch (e) {
      console.error("Fetch Error:", e);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  const fetchAiInsight = async (verse: SanZiJingVerse) => {
    if (isAiLoading || !verse) return;
    setIsAiLoading(true);
    setAiInsight('');
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `你是一位温和的国学老师。请针对这段经文：“${verse.content_raw}”，给孩子写一段简短、有趣的生活建议。100字以内。`,
      });
      setAiInsight(response.text || '智慧正在生成中...');
    } catch (e) {
      setAiInsight('AI 老师去休息啦，待会再试吧。');
    } finally {
      setIsAiLoading(false);
    }
  };

  useEffect(() => {
    if (activeTab === 'ai' && !aiInsight && verses[currentIdx]) {
      fetchAiInsight(verses[currentIdx]);
    }
  }, [activeTab, currentIdx, verses]);

  const playVerseSequence = useCallback((idx: number) => {
    if (!window.speechSynthesis || !verses[idx]) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(verses[idx].content_raw);
    utterance.lang = 'zh-CN';
    utterance.rate = 0.75;

    utterance.onboundary = (e) => {
      const textBefore = verses[idx].content_raw.substring(0, e.charIndex);
      const chineseOnlyBefore = textBefore.replace(/[^\u4e00-\u9fa5]/g, '');
      setCurrentCharIdx(chineseOnlyBefore.length);
    };

    utterance.onend = () => {
      setCurrentCharIdx(-1);
      if (isPlaying && idx < verses.length - 1) {
        setTimeout(() => {
           if(isPlaying) setCurrentIdx(prev => prev + 1);
        }, 600);
      } else {
        setIsPlaying(false);
      }
    };
    window.speechSynthesis.speak(utterance);
  }, [isPlaying, verses]);

  useEffect(() => {
    if (isPlaying) playVerseSequence(currentIdx);
    if (verseRefs.current[currentIdx]) {
      // 使用更平滑的滚动，避免“闪屏”感
      verseRefs.current[currentIdx]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, [currentIdx, isPlaying, playVerseSequence]);

  const activeVerse = verses[currentIdx];

  const handleCharClick = (char: string) => {
    setSelectedChar(char);
    setActiveTab('lexicon');
    speak(char, 0.6);
  };

  const HubView = () => {
    const dailyIdx = useMemo(() => new Date().getDate() % (verses.length || 1), [verses.length]);
    const dailyVerse = verses[dailyIdx];
    return (
      <div className="flex-1 flex flex-col p-6 overflow-y-auto no-scrollbar">
        <div className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-xl font-black text-[#1A1A1A] serif-font">三字经 · 国学馆</h2>
            <p className="text-[9px] text-slate-400 font-bold tracking-widest">WISDOM OF CLASSICS</p>
          </div>
          <button onClick={onClose} className="p-2 bg-white border border-[#e0d7c6] rounded-xl text-slate-400"><X size={18}/></button>
        </div>
        <div className="bg-white border border-[#e0d7c6] rounded-3xl p-8 mb-8 shadow-sm cursor-pointer" onClick={() => { setCurrentIdx(dailyIdx); setCurrentView('reader'); }}>
           <div className="flex flex-col items-center gap-4">
              <div className="text-5xl font-black serif-font text-[#1A1A1A] tracking-tighter">{dailyVerse?.content_chars.slice(0, 3).join('')}</div>
              <p className="text-sm text-slate-500 italic text-center leading-relaxed">“{dailyVerse?.translation_vernacular}”</p>
              <div className="px-6 py-2 bg-[#B22222] text-white text-[10px] font-black rounded-full uppercase tracking-widest mt-2">开始研读</div>
           </div>
        </div>
        <div className="grid grid-cols-2 gap-4">
           <HubCard icon={<BookOpen size={18}/>} label="全息长卷" onClick={() => setCurrentView('reader')} />
           <HubCard icon={<Sparkles size={18}/>} label="AI 陪读" onClick={() => { setCurrentView('reader'); setActiveTab('ai'); }} />
        </div>
      </div>
    );
  };

  const ReaderView = () => (
    <div className="flex-1 flex flex-col overflow-hidden bg-[#FDFBF7]">
      {/* 顶部控制栏 - 紧凑型设计 */}
      <header className="h-14 sm:h-16 bg-white border-b border-[#e0d7c6] flex items-center justify-between px-4 z-50 shrink-0">
         <button onClick={() => { setIsPlaying(false); setCurrentView('hub'); }} className="p-2 bg-[#F9F6F0] rounded-xl text-slate-400 hover:text-[#B22222] transition-colors">
           <ArrowLeft size={20} />
         </button>

         <div className="flex items-center gap-2 bg-[#1A1A1A] p-1.5 rounded-full shadow-lg">
            <button onClick={() => setCurrentIdx(prev => Math.max(0, prev - 1))} className="p-1.5 text-white/40 hover:text-white"><SkipBack size={16} fill="currentColor"/></button>
            <button onClick={() => setIsPlaying(!isPlaying)} className="w-9 h-9 bg-white rounded-full flex items-center justify-center active:scale-90 transition-all">
               {isPlaying ? <Pause size={18} className="text-[#1A1A1A]" fill="currentColor"/> : <Play size={18} className="text-[#1A1A1A] ml-0.5" fill="currentColor"/>}
            </button>
            <button onClick={() => setCurrentIdx(prev => Math.min(verses.length - 1, prev + 1))} className="p-1.5 text-white/40 hover:text-white"><SkipForward size={16} fill="currentColor"/></button>
         </div>

         <div className="flex gap-2">
            <ReaderAction icon={<Type size={16}/>} active={showPinyin} onClick={() => setShowPinyin(!showPinyin)} />
            <button className="p-2 bg-[#B22222] text-white rounded-xl active:scale-95"><Menu size={16}/></button>
         </div>
      </header>

      {/* 主展示区 - 垂直流动布局 */}
      <div className="flex-1 overflow-y-auto no-scrollbar scroll-smooth bg-[#FDFBF7]">

        {/* 原文展示区 - 6字一排，防止遮挡 */}
        <section className="px-6 py-10 md:py-16 flex flex-col items-center gap-20">
           {verses.map((v, i) => (
             <div 
               key={v.id} ref={el => { verseRefs.current[i] = el; }}
               className={`transition-all duration-500 cursor-pointer ${currentIdx === i ? 'opacity-100' : 'opacity-10'}`}
               onClick={() => { setCurrentIdx(i); setIsPlaying(false); }}
             >
                {/* 6字组合：例如 3字+3字 */}
                <div className="flex flex-wrap justify-center gap-x-4 md:gap-x-8 gap-y-6 max-w-2xl">
                   {v.content_chars.map((char, cIdx) => (
                     <div key={cIdx} className="flex flex-col items-center" onClick={(e) => { e.stopPropagation(); handleCharClick(char); }}>
                        {showPinyin && (
                          <span className={`text-[10px] sm:text-xs font-mono mb-2 ${currentIdx === i && currentCharIdx === cIdx ? 'text-[#B22222] font-black' : 'text-slate-300'}`}>
                            {v.content_pinyin[cIdx]}
                          </span>
                        )}
                        <span className={`text-4xl sm:text-6xl font-black serif-font tracking-tight leading-none transition-all ${currentIdx === i && currentCharIdx === cIdx ? 'text-[#1A1A1A] scale-110 drop-shadow-md' : 'text-[#333] opacity-80'}`}>
                           {char}
                        </span>
                     </div>
                   ))}
                </div>
             </div>
           ))}
        </section>

        {/* 截图中的 Tabs 区域 - 紧跟原文之后 */}
        <div className="sticky top-0 z-40 bg-white border-y border-[#e0d7c6] shadow-sm">
          <nav className="flex max-w-2xl mx-auto">
            {[
              { id: 'study', icon: <BookOpen size={16}/>, label: '义理' },
              { id: 'source', icon: <History size={16}/>, label: '典故' },
              { id: 'lexicon', icon: <Search size={16}/>, label: '字解' },
              { id: 'ai', icon: <Sparkles size={16}/>, label: 'AI' }
            ].map((tab: any) => (
              <button
                key={tab.id} onClick={() => setActiveTab(tab.id)}
                className={`flex-1 py-4 flex flex-col items-center gap-1.5 text-[10px] font-black transition-all relative ${activeTab === tab.id ? 'text-[#B22222]' : 'text-slate-400 hover:bg-slate-50'}`}
              >
                {tab.icon} {tab.label}
                {activeTab === tab.id && <div className="absolute bottom-0 w-full h-0.5 bg-[#B22222]" />}
              </button>
            ))}
          </nav>
        </div>

        {/* 详情解析区 */}
        <div className="max-w-2xl mx-auto p-6 md:p-10 pb-20">
           <AnimatePresence mode="wait">
              {activeTab === 'study' && (
                <motion.div key="study" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }} className="space-y-8">
                   <div>
                     <h4 className="text-[9px] font-black text-slate-300 uppercase tracking-widest mb-4 serif-font italic">现代译文</h4>
                     <p className="text-xl sm:text-2xl font-black text-[#1A1A1A] leading-relaxed italic serif-font">“{activeVerse?.translation_vernacular}”</p>
                   </div>
                   <div className="bg-[#F9F6F0] p-6 rounded-3xl border border-[#e0d7c6] shadow-inner">
                     <h4 className="text-[9px] font-black text-[#B22222] uppercase tracking-[0.2em] mb-4">深度导读</h4>
                     <p className="text-sm sm:text-base text-slate-600 leading-relaxed font-medium text-justify">{activeVerse?.interpretation_deep}</p>
                   </div>
                </motion.div>
              )}

              {activeTab === 'lexicon' && (
                <motion.div key="lexicon" initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-8">
                   {selectedChar && activeVerse?.char_analysis?.[selectedChar] ? (
                     <div className="space-y-6">
                        <div className="flex items-end gap-4 border-b border-[#f3efe6] pb-6">
                           <div className="text-6xl font-black text-[#1A1A1A] serif-font">{selectedChar}</div>
                           <div className="pb-1">
                              <div className="text-xl font-mono font-black text-[#B22222]">{activeVerse.char_analysis[selectedChar].pinyin}</div>
                              <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest">部首: {activeVerse.char_analysis[selectedChar].radical} | 笔画: {activeVerse.char_analysis[selectedChar].strokes}</div>
                           </div>
                        </div>
                        <div className="grid grid-cols-2 gap-3">
                           <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                              <h5 className="text-[8px] font-black text-slate-400 uppercase mb-1">字形构造</h5>
                              <div className="text-xs font-black text-[#1A1A1A]">{activeVerse.char_analysis[selectedChar].formation}</div>
                           </div>
                           <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                              <h5 className="text-[8px] font-black text-slate-400 uppercase mb-1">本义</h5>
                              <div className="text-xs font-black text-[#1A1A1A]">{activeVerse.char_analysis[selectedChar].original_meaning}</div>
                           </div>
                        </div>
                        <p className="text-xs text-slate-600 leading-relaxed italic border-l-2 border-[#B22222] pl-3">{activeVerse.char_analysis[selectedChar].evolution_story}</p>
                     </div>
                   ) : (
                     <div className="py-20 text-center opacity-10 flex flex-col items-center gap-3">
                        <Search size={48} />
                        <p className="text-sm font-black serif-font">点击原文汉字以解析</p>
                     </div>
                   )}
                </motion.div>
              )}

              {activeTab === 'source' && (
                <motion.div key="source" initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-6">
                   {activeVerse?.allusion_title ? (
                     <div className="bg-white p-6 rounded-3xl border-2 border-dashed border-[#e0d7c6]">
                        <div className="inline-block px-2 py-0.5 bg-[#B22222]/5 text-[#B22222] rounded-md text-[8px] font-black mb-3">{activeVerse.allusion_source}</div>
                        <h3 className="text-xl font-black serif-font text-[#1A1A1A] mb-4">{activeVerse.allusion_title}</h3>
                        <p className="text-sm text-slate-500 leading-loose italic">{activeVerse.allusion_context}</p>
                     </div>
                   ) : (
                     <div className="py-20 text-center opacity-10 flex flex-col items-center gap-3"><Compass size={48} /><p className="text-sm font-black serif-font">暂未收录典故</p></div>
                   )}
                </motion.div>
              )}

              {activeTab === 'ai' && (
                 <motion.div key="ai" initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-6">
                    <div className="p-8 bg-emerald-50/50 border border-emerald-100 rounded-3xl">
                       <div className="flex items-center justify-between mb-6 text-emerald-600">
                         <div className="flex items-center gap-2"><Mic2 size={16} /> <h4 className="text-[9px] font-black uppercase tracking-widest">AI 伴读建议</h4></div>
                         {isAiLoading && <Loader2 size={14} className="animate-spin" />}
                       </div>
                       {isAiLoading ? (
                         <div className="py-10 text-center"><p className="text-[10px] text-emerald-400 font-black tracking-widest animate-pulse">正在感悟经文...</p></div>
                       ) : (
                         <p className="text-lg font-bold text-emerald-900 leading-relaxed italic serif-font">“{aiInsight || '正在解读先贤智慧...' }”</p>
                       )}
                    </div>
                    <button onClick={() => activeVerse && fetchAiInsight(activeVerse)} className="w-full py-4 bg-white border border-emerald-100 text-emerald-600 rounded-2xl font-black text-[10px] flex items-center justify-center gap-2 hover:bg-emerald-50 transition-all">
                      <RefreshCw size={14} /> 换一个角度
                    </button>
                 </motion.div>
              )}
           </AnimatePresence>
        </div>
      </div>

      {/* 装饰页脚 */}
      <footer className="h-8 bg-white/90 border-t border-[#e0d7c6] px-6 flex items-center justify-between text-[8px] font-bold text-slate-400 italic shrink-0">
         <span>传承模式: 实时同步</span>
         <span className="uppercase tracking-widest">V3.5.0_Flow</span>
      </footer>
    </div>
  );

  return (
    <div className="fixed inset-0 z-[60] bg-[#FDFBF7] flex flex-col select-none overflow-hidden pb-[env(safe-area-inset-bottom)]">
      <div className="absolute inset-0 opacity-[0.06] pointer-events-none z-0 bg-[url('https://www.transparenttextures.com/patterns/rice-paper.png')]" />

      {isLoading ? (
        <div className="flex-1 flex flex-col items-center justify-center bg-[#FDFBF7]">
           <div className="w-10 h-10 border-[3px] border-[#B22222] border-t-transparent rounded-full animate-spin mb-4" />
           <p className="text-[9px] font-black tracking-widest text-[#B22222] uppercase">正在载入圣贤经文...</p>
        </div>
      ) : (
        <AnimatePresence mode="wait">
          {currentView === 'hub' ? <HubView key="hub" /> : <ReaderView key="reader" />}
        </AnimatePresence>
      )}

      <style>{`
        .serif-font { font-family: 'Noto Serif SC', serif; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        input[type=range] { accent-color: #B22222; }
      `}</style>
    </div>
  );
};

const HubCard = ({ icon, label, onClick }: any) => (
  <button onClick={onClick} className="bg-white border border-[#e0d7c6] p-4 rounded-2xl flex items-center gap-3 hover:border-[#B22222] transition-all group">
     <div className="w-10 h-10 bg-[#F9F6F0] rounded-xl flex items-center justify-center text-slate-400 group-hover:text-[#B22222] transition-colors">{icon}</div>
     <div className="text-xs font-black text-[#1A1A1A] serif-font">{label}</div>
  </button>
);

const ReaderAction = ({ icon, active, onClick }: any) => (
  <button onClick={onClick} className={`p-2 rounded-xl border transition-all ${active ? 'bg-[#1A1A1A] border-[#1A1A1A] text-white' : 'bg-white border-[#e0d7c6] text-slate-300'}`}>
    {icon}
  </button>
);

export default ThreeCharacterApp;

