                          </span>
                        )}
                        <span className={`text-3xl sm:text-5xl font-black serif-font tracking-tight leading-none transition-all ${currentIdx === i && currentCharIdx === cIdx ? 'text-[#1A1A1A] scale-110 drop-shadow-sm' : 'text-[#333] opacity-80'}`}>
