                           <div className="pb-1">
                              <div className="text-xl font-mono font-black text-[#B22222]">{activeVerse.char_analysis[selectedChar].pinyin}</div>
                              <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest">部首: {activeVerse.char_analysis[selectedChar].radical} | 笔画: {activeVerse.char_analysis[selectedChar].strokes}</div>
                           </div>
                        </div>
                        <div className="grid grid-cols-2 gap-3">
                           <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                              <h5 className="text-[8px] font-black text-slate-400 uppercase mb-1">字形构造</h5>
                              <div className="text-xs font-black text-[#1A1A1A]">{activeVerse.char_analysis[selectedChar].formation}</div>
                           </div>
                           <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                              <h5 className="text-[8px] font-black text-slate-400 uppercase mb-1">本义</h5>
